// Calculate time since registration started and determine recovery stage
const items = $input.all();
const now = Date.now();

const results = [];

for (const item of items) {
  const startedAt = new Date(item.json.created_at).getTime();
  const hoursElapsed = (now - startedAt) / (1000 * 60 * 60);
  const email = item.json.email || '';

  // Skip if no email was captured (beacon-only, no way to contact)
  if (!email) continue;

  // Determine recovery stage
  let stage = null;
  let subject = '';
  let urgency = '';

  if (hoursElapsed >= 1 && hoursElapsed < 6) {
    stage = '1h';
    subject = 'Almost done! Complete your registration';
    urgency = 'low';
  } else if (hoursElapsed >= 24 && hoursElapsed < 48) {
    stage = '24h';
    subject = "Don't miss out — spots are filling up";
    urgency = 'medium';
  } else if (hoursElapsed >= 72 && hoursElapsed < 96) {
    stage = '72h';
    subject = 'Last chance to register at this price';
    urgency = 'high';
  }

  // Skip if not in a recovery window or already handled
  if (!stage) continue;

  // Check if we've already sent this stage
  const sentStages = (item.json.recovery_stages_sent || '').split(',').map(s => s.trim());
  if (sentStages.includes(stage)) continue;

  results.push({
    json: {
      ...item.json,
      hours_elapsed: Math.round(hoursElapsed),
      recovery_stage: stage,
      email_subject: subject,
      urgency,
      reg_id: item.json.id || item.json.reg_id
    }
  });
}

if (results.length === 0) {
  return [{ json: { empty: true, message: 'No carts to recover' } }];
}

return results;

// Log that we sent a recovery email for this stage
const item = $input.first().json;

return [{
  json: {
    reg_id: item.reg_id,
    stage: item.recovery_stage,
    email: item.email,
    sent_at: new Date().toISOString(),
    event_id: item.event_id
  }
}];
